class TokenWindowManager {
  private maxTokens: number = 120000;
  private encoding: any;
  private messages: any[] = [];

  constructor() {
    // Load tiktoken-wasm or use approximation
  }

  addMessage(role: string, content: string): void {
    const msg = { role, content };
    this.messages.push(msg);

    // Trim from start until under limit
    while (this.getTotalTokens() > this.maxTokens) {
      this.messages.shift();
    }
  }

  getContext(): any[] {
    return [...this.messages];
  }

  private getTotalTokens(): number {
    return this.messages.reduce((sum, msg) => sum + this.estimateTokens(msg.content), 0);
  }

  private estimateTokens(text: string): number {
    return Math.ceil(text.length / 4);
  }
}

